# app/jobs/create_jira_tickets_job.rb\n\nclass CreateJiraTicketsJob < ApplicationJob\n  queue_as :default\n\n  def perform(brief_id)\n    brief = Brief.find_by(id: brief_id)\n    return unless brief\n\n    # Ensure the brief has structured data before trying to create tasks\n    unless brief.structured_data.present? && brief.structured_data[\'tasks\'].is_a?(Array)\n      Rails.logger.warn(\"Brief \#{brief_id} has no structured tasks to create Jira tickets from.\")\n      return\n    end\n\n    brief.structured_data[\'tasks\'].each do |task_data|\n      # Create a Task record\n      task = brief.tasks.create!(description: task_data[\'description\'], status: task_data[\'status\'])\n\n      # Use the JiraTicketCreator service to create an internal JiraTicket\n      JiraTicketCreator.new(task).create_ticket\n    end\n\n    brief.update!(status: \'tickets_created\')\n  rescue StandardError => e\n    brief.update!(status: \'failed\')\n    Rails.logger.error(\"Error creating Jira tickets for brief \#{brief_id}: \#{e.message}\")\n  end\nend